INSERT INTO destination_itineraries (slug, name, description, duration_days, difficulty_level, best_season, is_popular, created_at)
INSERT INTO itinerary_days (itinerary_id, day_number, title, description, accommodation, meals, distance_km, created_at) VALUES
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 1, 'Arrival in Kathmandu', 'Arrive in Kathmandu, transfer to hotel, trek briefing and gear check. Explore Thamel for last-minute supplies.', 'Hotel in Thamel', 'DINNER', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 2, 'Kathmandu to Chame', 'Early morning drive to Pokhara then continue by jeep to Chame, the district headquarters of Manang. Pass through lush subtropical forests and terraced hillsides.', 'Tea house in Chame', 'ALL', 190, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 3, 'Chame to Upper Pisang', 'Trek through deep forests along the Marsyangdi River valley. First views of Annapurna II and Lamjung Himal. Pass through the dramatic narrowing of the valley.', 'Tea house in Upper Pisang', 'ALL', 15, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 4, 'Upper Pisang to Manang', 'Traverse high pastures with stunning views of the Annapurna range. Visit Braga Monastery, one of the oldest in Nepal, en route to Manang.', 'Tea house in Manang', 'ALL', 20, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 5, 'Acclimatization Day in Manang', 'Essential rest day for altitude acclimatization. Hike to Gangapurna Lake or Ice Lake for stunning views. Visit the Himalayan Rescue Association clinic.', 'Tea house in Manang', 'ALL', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 6, 'Manang to Yak Kharka', 'Gradual ascent through juniper and scrub forest into the alpine zone. The landscape becomes more austere as you gain altitude. Pass yak pastures and mani walls.', 'Tea house in Yak Kharka', 'ALL', 12, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 7, 'Yak Kharka to Thorong Phedi', 'Trek along narrow trails above the Marsyangdi gorge. Arrive at Thorong Phedi at the base of Thorong La Pass. Early dinner and rest for the big crossing.', 'Tea house in Thorong Phedi', 'ALL', 10, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 8, 'Cross Thorong La to Muktinath', 'The big day. Pre-dawn start to cross Thorong La Pass at 5,416 meters. Breathtaking views of the Annapurna and Dhaulagiri ranges. Descend to the sacred town of Muktinath.', 'Tea house in Muktinath', 'ALL', 18, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 9, 'Muktinath to Jomsom', 'Descend through the dramatic Kali Gandaki valley, the deepest gorge in the world. Visit Muktinath Temple before heading down. Arrive in Jomsom, the gateway to Mustang.', 'Tea house in Jomsom', 'ALL', 22, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 10, 'Jomsom to Tatopani', 'Continue descending through the windy Kali Gandaki valley. Stop at Tatopani for a well-earned soak in natural hot springs. Enjoy the transition from arid back to subtropical.', 'Tea house in Tatopani', 'ALL', 25, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 11, 'Tatopani to Ghorepani', 'Steep climb through terraced rice paddies and rhododendron forests to Ghorepani, a popular viewpoint village at 2,860 meters.', 'Tea house in Ghorepani', 'ALL', 14, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 12, 'Ghorepani to Poon Hill to Tadapani', 'Pre-dawn hike to Poon Hill (3,210m) for a spectacular sunrise over the Annapurna and Dhaulagiri ranges. Continue through rhododendron forest to Tadapani.', 'Tea house in Tadapani', 'ALL', 12, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 13, 'Tadapani to Pokhara', 'Descend through lush forests and terraced fields to Nayapul. Drive to Pokhara for a well-deserved celebration. Boating on Phewa Lake.', 'Hotel in Pokhara', 'ALL', 15, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit'), 14, 'Pokhara to Kathmandu and Departure', 'Morning flight or scenic drive to Kathmandu. Final shopping in Thamel and departure.', NULL, 'BREAKFAST', 0, NOW());
