((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 1), (SELECT id FROM tourist_destinations WHERE slug = 'thamel'), 1, 'Arrival and preparation', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 5), (SELECT id FROM tourist_destinations WHERE slug = 'gangapurna-lake'), 1, 'Acclimatization hike', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 5), (SELECT id FROM tourist_destinations WHERE slug = 'ice-lake-manang'), 2, 'Optional higher acclimatization hike', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 8), (SELECT id FROM tourist_destinations WHERE slug = 'thorong-la-pass'), 1, 'Cross the 5,416m pass', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 8), (SELECT id FROM tourist_destinations WHERE slug = 'muktinath'), 2, 'Visit Muktinath Temple', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 9), (SELECT id FROM tourist_destinations WHERE slug = 'jomsom'), 1, 'Transit town for Mustang', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 11), (SELECT id FROM tourist_destinations WHERE slug = 'sarangkot'), 1, 'Sunrise viewpoint', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'classic-annapurna-circuit') AND day_number = 13), (SELECT id FROM tourist_destinations WHERE slug = 'phewa-lake'), 1, 'Celebration boat ride', NOW());
