INSERT INTO itinerary_days (itinerary_id, day_number, title, description, accommodation, meals, distance_km, created_at) VALUES
((SELECT id FROM destination_itineraries WHERE slug = 'kathmandu-valley-heritage'), 1, 'Arrival and Thamel Orientation', 'Arrive in Kathmandu and settle into your hotel in the vibrant Thamel district. Evening walking tour of Thamel''s bustling streets, sampling local cuisine and shopping for handicrafts.', 'Hotel in Thamel', 'DINNER', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'kathmandu-valley-heritage'), 2, 'Kathmandu Durbar Square and Swayambhunath', 'Morning exploration of Kathmandu Durbar Square with its ancient temples and the Kumari Ghar. Afternoon climb to Swayambhunath for panoramic valley views and the iconic Buddhist stupa.', 'Hotel in Thamel', 'BREAKFAST', 8, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'kathmandu-valley-heritage'), 3, 'Pashupatinath and Boudhanath', 'Visit the sacred Pashupatinath Temple complex on the banks of the Bagmati River. Afternoon at Boudhanath Stupa, walking the kora circuit with pilgrims and soaking in the Tibetan Buddhist atmosphere.', 'Hotel in Thamel', 'BREAKFAST', 12, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'kathmandu-valley-heritage'), 4, 'Patan and Bhaktapur', 'Morning in Patan exploring the exquisite Durbar Square and Golden Temple. Afternoon drive to Bhaktapur for the best-preserved medieval city in Nepal, visiting Nyatapola Temple and Pottery Square.', 'Hotel in Thamel', 'BREAKFAST', 25, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'kathmandu-valley-heritage'), 5, 'Nagarkot Sunrise and Departure', 'Pre-dawn drive to Nagarkot for spectacular Himalayan sunrise views. Return to Kathmandu for last-minute shopping and departure transfer.', NULL, 'BREAKFAST', 40, NOW());
