INSERT INTO itinerary_days (itinerary_id, day_number, title, description, accommodation, meals, distance_km, created_at) VALUES
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 1, 'Arrival in Pokhara', 'Fly or drive from Kathmandu to Pokhara. Settle into your lakeside hotel. Evening stroll along the Lakeside promenade and dinner at a lakeside restaurant.', 'Hotel in Pokhara Lakeside', 'DINNER', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 2, 'Sarangkot Sunrise and Paragliding', 'Pre-dawn drive to Sarangkot for the legendary Annapurna sunrise. After breakfast, tandem paragliding flight soaring above Phewa Lake with Himalayan backdrop. Afternoon free.', 'Hotel in Pokhara Lakeside', 'ALL', 12, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 3, 'Phewa Lake and Tal Barahi', 'Morning boating on Phewa Lake, visiting the island Tal Barahi Temple. Afternoon canoeing or kayaking on the lake. Evening meditation session at the Tibetan Refugee Camp.', 'Hotel in Pokhara Lakeside', 'ALL', 5, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 4, 'Davis Falls, Cave, and World Peace Pagoda', 'Visit the unique underground Davis Falls and sacred Gupteshwor Cave. Afternoon hike to the World Peace Pagoda for panoramic sunset views over the city and mountains.', 'Hotel in Pokhara Lakeside', 'ALL', 8, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 5, 'Seti River Gorge and International Mountain Museum', 'Morning visit to the dramatic Seti River Gorge and its deep canyons. Afternoon at the International Mountain Museum learning about Himalayan mountaineering history.', 'Hotel in Pokhara Lakeside', 'ALL', 10, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 6, 'Begnas and Rupa Lakes Day Trip', 'Full-day excursion to the peaceful Begnas and Rupa lakes east of Pokhara. Enjoy fishing, nature walks, and lunch at a lakeside restaurant away from the crowds.', 'Hotel in Pokhara Lakeside', 'ALL', 30, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week'), 7, 'Free Day and Departure', 'Free morning for shopping in Lakeside, a spa treatment, or last-minute activities. Afternoon departure or extension to other destinations.', NULL, 'BREAKFAST', 0, NOW());
