((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week') AND day_number = 4), (SELECT id FROM tourist_destinations WHERE slug = 'davis-falls'), 1, 'Unique underground waterfall', NOW()),
