((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week') AND day_number = 4), (SELECT id FROM tourist_destinations WHERE slug = 'world-peace-pagoda-pokhara'), 3, 'Sunset panorama', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week') AND day_number = 5), (SELECT id FROM tourist_destinations WHERE slug = 'seti-river-gorge'), 1, 'Dramatic river canyon', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'pokhara-adventure-week') AND day_number = 5), (SELECT id FROM tourist_destinations WHERE slug = 'international-mountain-museum'), 2, 'Museum visit', NOW()),
