INSERT INTO destination_itineraries (slug, name, description, duration_days, difficulty_level, best_season, is_popular, created_at)
INSERT INTO itinerary_days (itinerary_id, day_number, title, description, accommodation, meals, distance_km, created_at) VALUES
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 1, 'Arrival in Kathmandu', 'Arrive in Kathmandu and transfer to hotel. Trek briefing, gear check, and permit arrangements. Explore Thamel for any last supplies.', 'Hotel in Thamel', 'DINNER', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 2, 'Fly to Lukla, Trek to Phakding', 'Thrilling mountain flight to Lukla (2,840m). Begin the trek descending along the Dudh Koshi river valley through pine forests to Phakding.', 'Tea house in Phakding', 'ALL', 8, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 3, 'Phakding to Namche Bazaar', 'Cross suspension bridges over the Dudh Koshi and climb steeply to Namche Bazaar, the gateway to Everest. First glimpse of Everest and Ama Dablam from the trail.', 'Tea house in Namche Bazaar', 'ALL', 11, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 4, 'Acclimatization Day in Namche', 'Rest day for altitude acclimatization. Hike to the Everest View Hotel for stunning panoramas. Visit the Sherpa Culture Museum and explore Namche Bazaar.', 'Tea house in Namche Bazaar', 'ALL', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 5, 'Namche to Tengboche', 'Trek through rhododendron forests with spectacular views of Everest, Ama Dablam, and Thamserku. Visit Tengboche Monastery, the largest in the Khumbu.', 'Tea house in Tengboche', 'ALL', 10, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 6, 'Tengboche to Dingboche', 'Descend through forest and cross the Imja Khola river. Climb gradually to the wide valley of Dingboche with views of Island Peak and Makalu.', 'Tea house in Dingboche', 'ALL', 12, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 7, 'Acclimatization Day in Dingboche', 'Second acclimatization day. Hike up Nangkartshang Peak (5,083m) for incredible views of Makalu, Lhotse, and the Island Peak area.', 'Tea house in Dingboche', 'ALL', 0, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 8, 'Dingboche to Lobuche', 'Trek through the yak pastures of Thukla and past the memorial cairns for fallen climbers. Arrive at Lobuche beneath the towering Nuptse wall.', 'Tea house in Lobuche', 'ALL', 10, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 9, 'Lobuche to Gorak Shep to EBC', 'Early morning trek to Gorak Shep, then continue to Everest Base Camp (5,364m). Stand at the foot of the world''s highest mountain and witness theKhumbu Icefall.', 'Tea house in Gorak Shep', 'ALL', 13, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 10, 'Gorak Shep to Kala Patthar to Pheriche', 'Pre-dawn climb to Kala Patthar (5,545m) for the best Everest sunrise panorama. Descend to Pheriche through the Imja Valley.', 'Tea house in Pheriche', 'ALL', 16, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 11, 'Pheriche to Lukla', 'Long descent day retracing steps through Namche Bazaar to Lukla. Final celebration dinner with trekking crew.', 'Tea house in Lukla', 'ALL', 25, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express'), 12, 'Fly to Kathmandu and Departure', 'Morning flight from Lukla to Kathmandu. Transfer to international airport for departure or extend your stay.', NULL, 'BREAKFAST', 0, NOW());
