((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express') AND day_number = 1), (SELECT id FROM tourist_destinations WHERE slug = 'thamel'), 1, 'Arrival and preparation', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express') AND day_number = 3), (SELECT id FROM tourist_destinations WHERE slug = 'kathmandu-durbar-square'), 1, 'Brief cultural stop in Namche', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express') AND day_number = 5), (SELECT id FROM tourist_destinations WHERE slug = 'swayambhunath'), 1, 'Tengboche Monastery visit', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express') AND day_number = 9), (SELECT id FROM tourist_destinations WHERE slug = 'boudhanath'), 1, 'Everest Base Camp trek', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'everest-base-camp-express') AND day_number = 10), (SELECT id FROM tourist_destinations WHERE slug = 'pashupatinath'), 1, 'Kala Patthar sunrise', NOW());
