INSERT INTO itinerary_days (itinerary_id, day_number, title, description, accommodation, meals, distance_km, created_at) VALUES
((SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage'), 1, 'Arrival in Lumbini', 'Fly or drive to Bhairahawa and transfer to Lumbini. Afternoon visit to the Maya Devi Temple and marker stone marking the exact birthplace of Buddha. Evening meditation at the sacred pond.', 'Hotel in Lumbini', 'DINNER', 10, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage'), 2, 'Sacred Garden and Ashoka Pillar', 'Morning walk through the Sacred Garden visiting the Ashoka Pillar (249 BC), the sacred pool where Queen Mayadevi bathed, and the ancient ruins. Afternoon visit to Lumbini Museum and the World Peace Pagoda.', 'Hotel in Lumbini', 'ALL', 8, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage'), 3, 'Monastic Zone Exploration', 'Full day exploring the Monastic Zone. Visit monasteries from Thailand, Myanmar, China, South Korea, Germany, France, and Sri Lanka, each with unique architecture. Attend afternoon prayer session at a monastery.', 'Hotel in Lumbini', 'ALL', 5, NOW()),
((SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage'), 4, 'Tilaurakot and Departure', 'Morning excursion to Tilaurakot (ancient Kapilvastu), the childhood home of Prince Siddhartha. See the archaeological ruins and palace foundations. Return to Bhairahawa for departure.', NULL, 'ALL', 28, NOW());
