((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage') AND day_number = 1), (SELECT id FROM tourist_destinations WHERE slug = 'maya-devi-temple'), 1, 'Sacred birthplace', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage') AND day_number = 2), (SELECT id FROM tourist_destinations WHERE slug = 'lumbini-sacred-garden'), 1, 'Sacred Garden walkthrough', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage') AND day_number = 2), (SELECT id FROM tourist_destinations WHERE slug = 'ashoka-pillar'), 2, 'Ancient inscribed pillar', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage') AND day_number = 2), (SELECT id FROM tourist_destinations WHERE slug = 'lumbini-museum'), 3, 'Museum visit', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage') AND day_number = 2), (SELECT id FROM tourist_destinations WHERE slug = 'world-peace-pagoda-lumbini'), 4, 'Japanese peace stupa', NOW()),
((SELECT id FROM itinerary_days WHERE itinerary_id = (SELECT id FROM destination_itineraries WHERE slug = 'lumbini-buddhist-pilgrimage') AND day_number = 3), (SELECT id FROM tourist_destinations WHERE slug = 'monastic-zone-lumbini'), 1, 'International monasteries tour', NOW());
