-- Itinerary 1: Classic Annapurna Circuit (14 days)
-- =============================================
VALUES ('classic-annapurna-circuit', 'Classic Annapurna Circuit', 'The legendary Annapurna Circuit is one of the world''s great long-distance treks, circumnavigating the entire Annapurna massif through diverse landscapes from subtropical valleys to high alpine passes. Cross the mighty Thorong La Pass at 5,416 meters for jaw-dropping views.', 14, 'STRENUOUS', 'SPRING', true, NOW());




-- =============================================
-- Itinerary 2: Kathmandu Valley Heritage Tour (5 days)
-- =============================================
VALUES ('kathmandu-valley-heritage', 'Kathmandu Valley Heritage Tour', 'Explore the rich cultural tapestry of the Kathmandu Valley, home to seven UNESCO World Heritage Sites. Visit ancient Durbar Squares, sacred stupas, and atmospheric temples across three historic royal cities.', 5, 'EASY', 'AUTUMN', true, NOW());




-- =============================================
-- Itinerary 3: Pokhara Adventure Week (7 days)
-- =============================================
VALUES ('pokhara-adventure-week', 'Pokhara Adventure Week', 'Experience the adventure capital of Nepal with a packed week of paragliding, trekking, boating, and exploration around the stunning Pokhara Valley. Perfect for thrill-seekers who also appreciate natural beauty.', 7, 'MODERATE', 'AUTUMN', true, NOW());




-- =============================================
-- Itinerary 4: Everest Base Camp Express (12 days)
-- =============================================
VALUES ('everest-base-camp-express', 'Everest Base Camp Express', 'The iconic trek to the base of the world''s highest mountain, passing through Sherpa villages, ancient monasteries, and breathtaking Himalayan landscapes. Experience the hospitality of the Khumbu region and stand at the foot of Mount Everest.', 12, 'STRENUOUS', 'AUTUMN', true, NOW());




