-- Itinerary 5: Lumbini Buddhist Pilgrimage (4 days)
-- =============================================
VALUES ('lumbini-buddhist-pilgrimage', 'Lumbini Buddhist Pilgrimage', 'A spiritual journey to the birthplace of Lord Buddha and the sacred sites of the Lumbini region. Explore ancient temples, the Ashoka Pillar, and international monasteries in this UNESCO World Heritage landscape.', 4, 'EASY', 'WINTER', true, NOW());


